+/// Subject prefixes used by autogenerated coordination messages — file
+/// reservation force-releases, contact request notifications, and similar
+/// system traffic. These are hidden from the Messages screen by default so the
+/// list shows agent-authored content first; press `s` to reveal.
+const SYSTEM_MESSAGE_SUBJECT_PREFIXES: &[&str] = &[
+    "[file-reservations]",
+    "[file-reservation]",
+    "[reservation]",
+    "[reservations]",
+    "[build-slot]",
+    "[build-slots]",
+    "[contact]",
+    "[contacts]",
+    "[system]",
+    "Contact request from ",
+    "Contact request approved by ",
+    "Contact request denied by ",
+];
+
+/// Returns `true` for subjects produced by the system's coordination paths
+/// (file reservation notifications, contact request handshake mail, etc.).
+/// Real agent-authored messages return `false`.
+fn is_system_message_subject(subject: &str) -> bool {
+    let trimmed = subject.trim_start();
+    SYSTEM_MESSAGE_SUBJECT_PREFIXES
+        .iter()
+        .any(|prefix| trimmed.starts_with(prefix))
+}
