+    #[test]
+    fn is_system_message_subject_recognises_known_prefixes() {
+        assert!(is_system_message_subject(
+            "[file-reservations] Released stale lock on src/foo.rs"
+        ));
+        assert!(is_system_message_subject(
+            "[reservation] Renewed lock on docs/**"
+        ));
+        assert!(is_system_message_subject(
+            "[build-slot] Acquired worktree slot"
+        ));
+        assert!(is_system_message_subject(
+            "Contact request from RubyKnoll"
+        ));
+        assert!(is_system_message_subject(
+            "  [system] Heartbeat OK"
+        ));
+    }
+
+    #[test]
+    fn is_system_message_subject_passes_through_real_messages() {
+        assert!(!is_system_message_subject(
+            "[br-123] Drop-close regression repro plan"
+        ));
+        assert!(!is_system_message_subject(
+            "Thoughts on the share bundle config schema"
+        ));
+        assert!(!is_system_message_subject(""));
+    }
+
+    #[test]
+    fn screen_defaults_to_hiding_system_messages() {
